$toolDefinition_rss_to_sqlite = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'rss_to_sqlite',
    'description' => 'Batch-harvest multiple RSS/Atom feeds into a SQLite database with deduplication, full-text search (FTS5), and automatic topic tagging. Fetches each feed via PHP streams, parses with SimpleXML (handles both RSS 2.0 and Atom namespaces), deduplicates by GUID/link, stores all items with FTS5 indexing, and tags items by matching against configurable topic keywords. Goes beyond feed_watcher (single-feed diff) by building a searchable multi-source archive. First batch feed aggregation capability in the ecosystem. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
