        array (
          'type' => 'array',
          'description' => 'Array of RSS/Atom feed URLs to harvest (e.g. [\'https://hnrss.org/frontpage\',\'https://feeds.bbci.co.uk/news/rss.xml\']).',
          'items' => 
          array (
            'type' => 'string',
          ),
        ),
        'db_name' => 
        array (
