          'description' => 'SQLite database filename in workspace (default: \'rss_archive.sqlite\').',
        ),
        'max_items_per_feed' => 
        array (
          'type' => 'integer',
          'description' => 'Maximum items to collect per feed (1-200, default: 50).',
