        0 => 'feeds',
      ),
    ),
  ),
);

if (! function_exists('rss_to_sqlite')) {
    function rss_to_sqlite($feeds, $db_name = null, $max_items_per_feed = null, $timeout = null, $drop_existing = null, $topics = null)
    {
        $feeds = $feeds ?? [];
        $db_name = $db_name ?? 'rss_archive.sqlite';
        $max_items_per_feed = (int)($max_items_per_feed ?? 50);
        $timeout = (int)($timeout ?? 20);
        $drop_existing = $drop_existing ?? false;

        if (empty($feeds)) {
            return ['success' => false, 'error' => 'At least one feed URL is required.'];
        }
        if ($max_items_per_feed < 1) $max_items_per_feed = 1;
        if ($max_items_per_feed > 200) $max_items_per_feed = 200;

        // Default topic keywords
        $topic_keywords = $topics ?? [
            'tech' => ['software', 'AI', 'artificial intelligence', 'machine learning', 'cloud', 'app', 'code', 'programming', 'startup', 'data', 'algorithm', 'API', 'developer', 'github', 'open source'],
            'science' => ['research', 'study', 'scientist', 'discovery', 'space', 'nasa', 'physics', 'chemistry', 'biology', 'climate', 'gene', 'quantum', 'telescope'],
            'business' => ['market', 'stock', 'economy', 'trade', 'revenue', 'profit', 'CEO', 'investment', 'IPO', 'merger', 'acquisition', 'bank', 'finance'],
            'policy' => ['government', 'law', 'regulation', 'congress', 'senate', 'president', 'election', 'vote', 'bill', 'court', 'judge', 'legislation', 'policy'],
            'security' => ['hack', 'breach', 'vulnerability', 'exploit', 'malware', 'ransomware', 'cyber', 'CVE', 'patch', 'zero-day', 'phishing', 'attack'],
        ];

        // Set up SQLite
        $workspace = __DIR__ . '/../workspace';
        if (!is_dir($workspace)) {
            mkdir($workspace, 0755, true);
        }
        $db_path = $workspace . '/' . $db_name;

        try {
            $pdo = new PDO("sqlite:$db_path");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $pdo->exec("PRAGMA journal_mode=WAL");
            $pdo->exec("PRAGMA busy_timeout=5000");
        } catch (Exception $e) {
            return ['success' => false, 'error' => 'Failed to open SQLite database: ' . $e->getMessage()];
        }

        // Drop existing if requested
        if ($drop_existing) {
            $pdo->exec("DROP TABLE IF EXISTS feed_items");
            $pdo->exec("DROP TABLE IF EXISTS feed_items_fts");
            $pdo->exec("DROP TABLE IF EXISTS feed_sources");
        }

        // Create tables
        $pdo->exec("CREATE TABLE IF NOT EXISTS feed_sources (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            url TEXT UNIQUE NOT NULL,
            title TEXT,
            last_harvested TEXT,
            item_count INTEGER DEFAULT 0,
            error_count INTEGER DEFAULT 0
        )");

        $pdo->exec("CREATE TABLE IF NOT EXISTS feed_items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            source_id INTEGER,
            guid TEXT,
            title TEXT,
            link TEXT,
            description TEXT,
            pub_date TEXT,
            author TEXT,
            category TEXT,
            topics TEXT,
            harvested_at TEXT,
            UNIQUE(source_id, guid),
            FOREIGN KEY(source_id) REFERENCES feed_sources(id)
        )");

        // Create FTS5 virtual table
        $pdo->exec("CREATE VIRTUAL TABLE IF NOT EXISTS feed_items_fts USING fts5(
            title, description, topics,
            content='feed_items', content_rowid='id'
        )");

        // Create triggers for FTS sync
        $pdo->exec("CREATE TRIGGER IF NOT EXISTS feed_items_ai AFTER INSERT ON feed_items BEGIN
            INSERT INTO feed_items_fts(rowid, title, description, topics) VALUES (new.id, new.title, new.description, new.topics);
        END");
        $pdo->exec("CREATE TRIGGER IF NOT EXISTS feed_items_ad AFTER DELETE ON feed_items BEGIN
            INSERT INTO feed_items_fts(feed_items_fts, rowid, title, description, topics) VALUES('delete', old.id, old.title, old.description, old.topics);
        END");
        $pdo->exec("CREATE TRIGGER IF NOT EXISTS feed_items_au AFTER UPDATE ON feed_items BEGIN
            INSERT INTO feed_items_fts(feed_items_fts, rowid, title, description, topics) VALUES('delete', old.id, old.title, old.description, old.topics);
            INSERT INTO feed_items_fts(rowid, title, description, topics) VALUES (new.id, new.title, new.description, new.topics);
        END");

        // Preload existing source IDs into a map
        $existing_sources = [];
        $source_stmt = $pdo->query("SELECT id, url FROM feed_sources");
        while ($row = $source_stmt->fetch(PDO::FETCH_ASSOC)) {
            $existing_sources[$row['url']] = (int)$row['id'];
        }

        // Helper: get or create source ID (stable — no REPLACE that changes IDs)
        $get_source_id = function($url, $title, $now) use ($pdo, &$existing_sources) {
            if (isset($existing_sources[$url])) {
                // Update timestamp and title
                $upd = $pdo->prepare("UPDATE feed_sources SET title = ?, last_harvested = ? WHERE id = ?");
                $upd->execute([$title, $now, $existing_sources[$url]]);
                return $existing_sources[$url];
            }
            
            // Insert new source
            $ins = $pdo->prepare("INSERT INTO feed_sources (url, title, last_harvested, item_count, error_count) VALUES (?, ?, ?, 0, 0)");
            $ins->execute([$url, $title, $now]);
            $new_id = (int)$pdo->lastInsertId();
            $existing_sources[$url] = $new_id;
            return $new_id;
        };

        // Helper: assign topics
        $assign_topics = function($text) use ($topic_keywords) {
            $matched = [];
            $lower = strtolower($text);
            foreach ($topic_keywords as $topic => $keywords) {
                foreach ($keywords as $kw) {
                    if (stripos($lower, $kw) !== false) {
                        $matched[$topic] = true;
                        break;
                    }
                }
            }
            return empty($matched) ? 'general' : implode(',', array_keys($matched));
        };

        // Helper: fetch and parse a feed
        $fetch_feed = function($url) use ($timeout) {
            $context = stream_context_create([
                'http' => [
                    'method' => 'GET',
                    'timeout' => $timeout,
                    'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/rss+xml, application/atom+xml, application/xml, text/xml\r\n",
                    'ignore_errors' => true,
                    'follow_location' => 1,
                    'max_redirects' => 5,
                ]
            ]);
            
            $body = @file_get_contents($url, false, $context);
            if ($body === false) {
                return ['error' => 'Failed to fetch feed'];
            }
            
            libxml_use_internal_errors(true);
            $xml = simplexml_load_string($body);
            if ($xml === false) {
                $errors = libxml_get_errors();
                libxml_clear_errors();
                return ['error' => 'Failed to parse XML: ' . ($errors[0]->message ?? 'unknown')];
            }
            libxml_clear_errors();
            
            $items = [];
            $feed_title = '';
            
            if (isset($xml->channel)) {
                $feed_title = (string)($xml->channel->title ?? '');
                foreach ($xml->channel->item as $item) {
                    $ns = $item->children('http://purl.org/dc/elements/1.1/');
                    $items[] = [
                        'title' => (string)($item->title ?? ''),
                        'link' => (string)($item->link ?? ''),
                        'description' => strip_tags((string)($item->description ?? '')),
                        'pub_date' => (string)($item->pubDate ?? ''),
                        'author' => (string)($item->author ?? $ns->creator ?? ''),
                        'guid' => (string)($item->guid ?? $item->link ?? ''),
                        'category' => (string)($item->category ?? ''),
                    ];
                }
            } elseif (isset($xml->entry)) {
                $feed_title = (string)($xml->title ?? '');
                foreach ($xml->entry as $entry) {
                    $link = '';
                    foreach ($entry->link as $l) {
                        $attrs = $l->attributes();
                        if ((string)($attrs['rel'] ?? 'alternate') === 'alternate' || $link === '') {
                            $link = (string)($attrs['href'] ?? '');
                        }
                    }
                    $items[] = [
                        'title' => (string)($entry->title ?? ''),
                        'link' => $link,
                        'description' => strip_tags((string)($entry->summary ?? $entry->content ?? '')),
                        'pub_date' => (string)($entry->updated ?? $entry->published ?? ''),
                        'author' => (string)($entry->author->name ?? ''),
                        'guid' => (string)($entry->id ?? $link),
                        'category' => (string)($entry->category[0]['term'] ?? ''),
                    ];
                }
            } else {
                return ['error' => 'Unknown feed format'];
            }
            
            return [
                'title' => $feed_title,
                'items' => $items,
                'item_count' => count($items),
            ];
        };

        // Harvest all feeds
        $harvest_report = [];
        $total_new = 0;
        $total_dupes = 0;
        $total_errors = 0;
        $all_topics = [];
        $now = date('Y-m-d H:i:s');

        $stmt_insert = $pdo->prepare("INSERT OR IGNORE INTO feed_items (source_id, guid, title, link, description, pub_date, author, category, topics, harvested_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");

        foreach ($feeds as $feed_url) {
            $feed_url = trim($feed_url);
            if (empty($feed_url)) continue;
            
            $result = $fetch_feed($feed_url);
            
            if (isset($result['error'])) {
                $harvest_report[] = [
                    'url' => $feed_url,
                    'status' => 'error',
                    'error' => $result['error'],
                    'new_items' => 0,
                    'duplicates' => 0,
                ];
                $total_errors++;
                continue;
            }
            
            $source_id = $get_source_id($feed_url, $result['title'], $now);
            
            $new_count = 0;
            $dupe_count = 0;
            
            foreach ($result['items'] as $i => $item) {
                if ($i >= $max_items_per_feed) break;
                if (empty($item['title']) && empty($item['guid'])) continue;
                
                $guid = !empty($item['guid']) ? $item['guid'] : ($item['link'] ?: md5($item['title']));
                $topics = $assign_topics($item['title'] . ' ' . $item['description']);
                
                $stmt_insert->execute([
                    $source_id,
                    mb_substr($guid, 0, 500),
                    mb_substr($item['title'], 0, 500),
                    mb_substr($item['link'], 0, 1000),
                    mb_substr($item['description'], 0, 5000),
                    mb_substr($item['pub_date'], 0, 100),
                    mb_substr($item['author'], 0, 200),
                    mb_substr($item['category'], 0, 200),
                    $topics,
                    $now,
                ]);
                
                if ($stmt_insert->rowCount() > 0) {
                    $new_count++;
                    foreach (explode(',', $topics) as $t) {
                        $all_topics[$t] = ($all_topics[$t] ?? 0) + 1;
                    }
                } else {
                    $dupe_count++;
                }
            }
            
            $harvest_report[] = [
                'url' => $feed_url,
                'feed_title' => $result['title'],
                'status' => 'ok',
                'items_in_feed' => count($result['items']),
                'new_items' => $new_count,
                'duplicates' => $dupe_count,
            ];
            
            $total_new += $new_count;
            $total_dupes += $dupe_count;
        }

        // Get total DB stats
        $total_items = (int)$pdo->query("SELECT COUNT(*) FROM feed_items")->fetchColumn();
        $total_sources = (int)$pdo->query("SELECT COUNT(*) FROM feed_sources")->fetchColumn();

        // FTS sample
        $fts_test = $pdo->query("SELECT title FROM feed_items_fts WHERE feed_items_fts MATCH 'technology OR security OR research' LIMIT 5")->fetchAll(PDO::FETCH_COLUMN);

        arsort($all_topics);
        $topic_summary = array_slice($all_topics, 0, 10);

        return [
            'success' => true,
            'database' => $db_path,
            'db_name' => $db_name,
            'harvest_time' => $now,
            'summary' => [
                'feeds_processed' => count($harvest_report),
                'feeds_successful' => count(array_filter($harvest_report, fn($r) => $r['status'] === 'ok')),
                'feeds_failed' => $total_errors,
                'total_new_items' => $total_new,
                'total_duplicates' => $total_dupes,
                'database_total_items' => $total_items,
                'database_total_sources' => $total_sources,
            ],
            'topics' => $topic_summary,
            'fts_sample' => $fts_test,
            'feeds' => $harvest_report,
        ];
    }
}
